  signal acq_data_marsh_demux_reg           : std_logic_vector(g_acq_data_width-1 downto 0);
  signal acq_trig_demux_reg                 : std_logic;
  signal acq_dvalid_demux_reg               : std_logic;
  signal acq_id_demux_reg                   : t_acq_id;

begin

