       acq_data_marsh_demux_reg <= acq_data_marsh_demux(g_acq_data_width-1 downto 0);
       acq_dvalid_demux_reg <= acq_dvalid_demux;
       acq_id_demux_reg <= acq_id_demux;
       acq_trig_demux_reg <= acq_trig_demux;
